#include<iostream>#include<vector>#include<algorithm>#include<string>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll x;        cin>>x;        ll n=x;        ll sum=0;        while(n!=0){            sum+=n%10;            n/=10;        }        string s=to_string(x);        vector<ll> v;        for (int i = 0; i < s.length(); i++) {            if (i == 0) {                v.push_back(s[i] - '0' - 1);            } else {                v.push_back(s[i] - '0');            }        }        if(sum<=9){            cout<<0<<"\n";         }        else{            sort(v.rbegin(),v.rend());            ll ans=0;            for(int a:v){                sum-=a;                ans++;                if(sum<=9){                    break;                }            }            cout<<ans<<"\n";        }     }}